solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>

void *double_value(void *arg) {
    int *p = (int *)arg;
    *p *= 2;
    return NULL;
}

int run_thread(int *val) {
    pthread_t tid;
    if (pthread_create(&tid, NULL, double_value, val) != 0)
        return -1;
    if (pthread_join(tid, NULL) != 0)
        return -1;
    return 0;
}

int main(void) {
    int x = 5;
    if (run_thread(&x) == 0)
        printf("%d\n", x);
    return 0;
}

validation.test_code:
static int g_val;

void test_double_value_via_thread(void) {
    g_val = 7;
    int rc = run_thread(&g_val);
    TEST_ASSERT_EQUAL_INT(0, rc);
    TEST_ASSERT_EQUAL_INT(14, g_val);
}

void test_double_value_zero(void) {
    g_val = 0;
    run_thread(&g_val);
    TEST_ASSERT_EQUAL_INT(0, g_val);
}

void test_double_value_negative(void) {
    g_val = -3;
    run_thread(&g_val);
    TEST_ASSERT_EQUAL_INT(-6, g_val);
}

void test_run_thread_returns_zero(void) {
    int x = 1;
    int rc = run_thread(&x);
    TEST_ASSERT_EQUAL_INT(0, rc);
}

int main(void) {
    RUN_TEST(test_double_value_via_thread);
    RUN_TEST(test_double_value_zero);
    RUN_TEST(test_double_value_negative);
    RUN_TEST(test_run_thread_returns_zero);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
